attributes.visState:
{
  "title": "alertas por severidad",
  "type": "vega",
  "aggs": [],
  "params": {
    "spec": "{
  "$schema": "https://vega.github.io/schema/vega-lite/v5.json",
  "title": "Alertas por severidad",
  "data": {
    "url": {
      "index": "wazuh-alerts-*",
      "body": {
        "size": 0,
        "aggs": {
          "niveles": {
            "range": {
              "field": "rule.level",
              "ranges": [
                { "to": 4, "key": "Baja" },
                { "from": 4, "to": 7, "key": "Media" },
                { "from": 7, "to": 9, "key": "Alta" },
                { "from": 9, "key": "Crítica" }
              ]
            }
          }
        }
      }
    },
    "format": { "property": "aggregations.niveles.buckets" }
  },
  "transform": [
    {
      "calculate": "datum.key == 'Baja' ? '0 - 3' : datum.key == 'Media' ? '4 - 6' : datum.key == 'Alta' ? '7 - 8' : '9 +'",
      "as": "rango"
    }
  ],
  "selection": {
    "highlight": { "type": "single", "on": "mouseover", "fields": ["key"] }
  },
  "mark": "bar",
  "encoding": {
    "x": {
      "field": "key",
      "type": "ordinal",
      "title": "Severidad",
      "scale": {
        "domain": ["Baja", "Media", "Alta", "Crítica"]
      }
    },
    "y": {
      "field": "doc_count",
      "type": "quantitative",
      "title": "Número de alertas"
    },
    "color": {
      "condition": {
        "selection": "highlight",
        "field": "key",
        "type": "nominal",
        "scale": {
          "domain": ["Baja", "Media", "Alta", "Crítica"],
          "range": ["#4CAF50", "#FFC107", "#FF5722", "#F44336"]
        }
      },
      "value": "lightgray"
    },
    "tooltip": [
      { "field": "key", "title": "Severidad" },
      { "field": "doc_count", "title": "Número de alertas" },
      { "field": "rango", "title": "Rango" }
    ]
  }
}
"
  }
}
